# Remplacer l'ancienne grille
old_pattern = r'<div class="crypto-coin-grid" id="cp-coins">.*?</div>\s*(?=\s*<button class="btn-p"[^>]*id="cp-pay-btn")'
if re.search(old_pattern, html, re.DOTALL):
    html = re.sub(old_pattern, new_grid + '\n      ', html, flags=re.DOTALL)
    print("OK - Grille 25 coins remplacee")
else:
    print("ERREUR - Pattern non trouve")
    # Chercher pattern alternatif
    alt = r'<div class="crypto-coin-grid" id="cp-coins">.*?</div>'
    matches = re.findall(alt, html, re.DOTALL)
    print(f"Matches trouves: {len(matches)}")
    if matches:
        # Prendre le premier et le remplacer
        html = html.replace(matches[0], new_grid, 1)
        print("OK - Remplacement alternatif effectue")

# Mettre à jour le COIN_MAP dans server-at.js aussi (optionnel - déjà géré côté backend)

with open('zama.html', 'w', encoding='utf-8') as f:
    f.write(html)

